  1→<!DOCTYPE html>
  2→<html lang="zh-CN">
  3→<head>
  4→  <meta charset="UTF-8">
  5→  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  6→  <title>大纲编辑器</title>
  7→  <style>
  8→    /* ── Themes ───────────────────────────────────────────────────── */
  9→    body {
 10→      --bg:#111111; --surface:#191919; --surface2:#1e1e1e; --surface3:#252525;
 11→      --border:#222222; --border2:#303030;
 12→      --text:#c8c8c8; --text-dim:#5a5a5a; --text-muted:#323232;
 13→      --title-color:#e0e0e0; --body-color:#787878;
 14→      --accent:#5a87e8; --dot-on:#5a87e8; --dot-off:#282828;
 15→      --selected-bg:#131b2d; --selected-border:#3d60b8;
 16→      --act-color:#484848; --ch-color:#5a5a5a;
 17→    }
 18→    body[data-theme="moon"] {
 19→      --bg:#1c1a18; --surface:#242220; --surface2:#292724; --surface3:#302e2a;
 20→      --border:#2a2826; --border2:#3a3835;
 21→      --text:#ded8cc; --text-dim:#7a7268; --text-muted:#484440;
 22→      --title-color:#f0ead8; --body-color:#a09080;
 23→      --accent:#9878e0; --dot-on:#9878e0; --dot-off:#302e2a;
 24→      --selected-bg:#1e1a2a; --selected-border:#7050c0;
 25→      --act-color:#605850; --ch-color:#78706a;
 26→    }
 27→    body[data-theme="paper"] {
 28→      --bg:#f0ead8; --surface:#e8e2d0; --surface2:#ddd8c8; --surface3:#d5d0c0;
 29→      --border:#d8d2c0; --border2:#c0baa8;
 30→      --text:#2a2420; --text-dim:#706050; --text-muted:#b0a890;
 31→      --title-color:#181410; --body-color:#6a5a48;
 32→      --accent:#3a60a8; --dot-on:#3a60a8; --dot-off:#c8c0b0;
 33→      --selected-bg:#e0d8c8; --selected-border:#3a60a8;
 34→      --act-color:#a09080; --ch-color:#605040;
 35→    }
 36→    body[data-theme="ocean"] {
 37→      --bg:#0b141e; --surface:#111c28; --surface2:#152030; --surface3:#1a2838;
 38→      --border:#162030; --border2:#1e2e40;
 39→      --text:#b0c8d8; --text-dim:#486070; --text-muted:#253545;
 40→      --title-color:#d0e4f0; --body-color:#5a7888;
 41→      --accent:#38a0d0; --dot-on:#38a0d0; --dot-off:#182838;
 42→      --selected-bg:#101c30; --selected-border:#2880b0;
 43→      --act-color:#405868; --ch-color:#4a6878;
 44→    }
 45→    body[data-theme="amber"] {
 46→      --bg:#160e04; --surface:#1e1408; --surface2:#24180a; --surface3:#2c1e0e;
 47→      --border:#201408; --border2:#302010;
 48→      --text:#d8c090; --text-dim:#806040; --text-muted:#3c2810;
 49→      --title-color:#f0d898; --body-color:#8a6a30;
 50→      --accent:#c07820; --dot-on:#c07820; --dot-off:#2a1c08;
 51→      --selected-bg:#1c1208; --selected-border:#a06010;
 52→      --act-color:#6a4820; --ch-color:#806030;
 53→    }
 54→
 55→    /* ── Base ─────────────────────────────────────────────────────── */
 56→    :root { --serif:'Georgia','STSong','宋体',serif; --sans:-apple-system,'PingFang SC','Helvetica Neue',sans-serif; }
 57→    * { box-sizing:border-box; margin:0; padding:0; }
 58→    body { background:var(--bg); color:var(--text); font-family:var(--sans); height:100vh; display:flex; flex-direction:column; overflow:hidden; transition:background .3s,color .3s; }
 59→
 60→    /* ── Top bar ── */
 61→    .topbar { height:44px; background:var(--surface); border-bottom:1px solid var(--border); display:flex; align-items:center; padding:0 14px; gap:10px; flex-shrink:0; user-select:none; }
 62→    .topbar-title { font-size:13px; font-weight:600; color:var(--title-color); max-width:300px; white-space:nowrap; overflow:hidden; text-overflow:ellipsis; }
 63→    .topbar-meta { font-size:11px; color:var(--text-muted); }
 64→    .sep { color:var(--border2); }
 65→    .spacer { flex:1; }
 66→    .view-toggle { display:flex; border:1px solid var(--border2); border-radius:5px; overflow:hidden; }
 67→    .view-toggle button { background:none; border:none; color:var(--text-dim); padding:4px 10px; font-size:11px; cursor:pointer; font-family:var(--sans); transition:all .15s; }
 68→    .view-toggle button.active { background:var(--surface3); color:var(--text); }
 69→    .btn { background:none; border:1px solid var(--border2); color:var(--text-dim); padding:4px 11px; border-radius:5px; font-size:11px; cursor:pointer; font-family:var(--sans); transition:all .15s; white-space:nowrap; position:relative; }
 70→    .btn:hover { border-color:var(--accent); color:var(--accent); }
 71→    #fileInput { display:none; }
 72→
 73→    /* ── Theme picker ── */
 74→    .theme-wrap { position:relative; }
 75→    .theme-panel { display:none; position:absolute; top:calc(100% + 8px); right:0; background:var(--surface); border:1px solid var(--border2); border-radius:8px; padding:12px; width:230px; z-index:200; box-shadow:0 8px 24px rgba(0,0,0,.4); }
 76→    .theme-panel.open { display:block; }
 77→    .theme-panel-title { font-size:10px; color:var(--text-dim); letter-spacing:.06em; text-transform:uppercase; margin-bottom:10px; }
 78→    .theme-grid { display:grid; grid-template-columns:1fr 1fr; gap:6px; }
 79→    .theme-opt { display:flex; align-items:center; gap:8px; padding:7px 9px; border-radius:6px; cursor:pointer; border:1px solid transparent; transition:all .15s; }
 80→    .theme-opt:hover { background:var(--surface2); }
 81→    .theme-opt.active { border-color:var(--accent); }
 82→    .theme-swatch { width:22px; height:22px; border-radius:5px; flex-shrink:0; border:1px solid rgba(255,255,255,.08); }
 83→    .theme-name { font-size:12px; color:var(--text); }
 84→    .theme-opt.active .theme-name { color:var(--accent); }
 85→
 86→    /* ── Toast ── */
 87→    .toast { position:fixed; bottom:20px; left:50%; transform:translateX(-50%); background:var(--surface3); border:1px solid var(--border2); color:var(--text); padding:7px 15px; border-radius:6px; font-size:12px; opacity:0; transition:opacity .3s; pointer-events:none; z-index:999; white-space:nowrap; }
 88→    .toast.show { opacity:1; }
 89→    .toast.error { border-color:#c05050; color:#e07070; }
 90→
 91→    /* ── Drop ── */
 92→    .drop-overlay { display:none; position:fixed; inset:0; background:rgba(90,135,232,.06); border:2px dashed var(--accent); z-index:100; pointer-events:none; align-items:center; justify-content:center; font-size:14px; color:var(--accent); }
 93→    body.dragging .drop-overlay { display:flex; }
 94→
 95→    /* ── Layout ── */
 96→    .main { display:flex; flex:1; overflow:hidden; }
 97→
 98→    /* ── Outline panel ── */
 99→    .outline-panel { flex:1; overflow-y:auto; padding:6px 0 40px; min-width:0; }
100→    .outline-panel::-webkit-scrollbar { width:3px; }
101→    .outline-panel::-webkit-scrollbar-thumb { background:var(--border2); border-radius:2px; }
102→    .empty-state { display:flex; flex-direction:column; align-items:center; justify-content:center; height:100%; gap:8px; color:var(--text-muted); font-size:13px; text-align:center; line-height:1.7; padding:40px; }
103→    .empty-icon { font-size:26px; opacity:.35; margin-bottom:6px; }
104→
105→    .act-header { display:flex; align-items:center; gap:6px; padding:12px 16px 5px; cursor:pointer; font-size:10px; font-weight:700; color:var(--act-color); letter-spacing:.1em; text-transform:uppercase; }
106→    .act-header:hover { color:var(--text-dim); }
107→    .chapter-header { display:flex; align-items:center; gap:6px; padding:5px 16px 5px 30px; cursor:pointer; font-size:11.5px; font-weight:600; color:var(--ch-color); border-bottom:1px solid var(--border); }
108→    .chapter-header:hover { background:var(--surface2); }
109→    .chevron { width:10px; height:10px; flex-shrink:0; transition:transform .4s ease; color:var(--text-muted); }
110→    .collapsed > .act-header .chevron, .collapsed > .chapter-header .chevron { transform:rotate(-90deg); }
111→    .act-body, .chapter-body { overflow:hidden; max-height:4000px; transition:max-height .45s ease; }
112→    .act-body.hidden, .chapter-body.hidden { max-height:0; }
113→
114→    .scene-item { border-bottom:1px solid var(--border); }
115→    .scene-item.selected { background:var(--selected-bg); }
116→
117→    .scene-content { padding:8px 16px 9px 36px; min-width:0; }
118→    .scene-title-row { display:flex; align-items:center; margin-bottom:3px; }
119→    .scene-left { display:flex; align-items:center; gap:6px; width:52px; flex-shrink:0; }
120→    .dot-btn { display:flex; align-items:center; justify-content:center; width:14px; flex-shrink:0; cursor:pointer; }
121→    .dot { width:6px; height:6px; border-radius:50%; background:var(--dot-off); transition:background .2s; flex-shrink:0; }
122→    .dot.on { background:var(--dot-on); }
123→    .dot-btn:hover .dot { background:var(--accent); opacity:.7; }
124→    .scene-id { font-size:10px; color:var(--text-muted); letter-spacing:.05em; flex-shrink:0; }
125→    .scene-title-text { font-size:13px; font-weight:600; color:var(--title-color); line-height:1.4; outline:none; border-radius:3px; padding:1px 3px; margin:-1px -3px; cursor:text; }
126→    .scene-title-text:focus { background:var(--surface3); }
127→    .scene-body-text { font-size:12.5px; color:var(--body-color); line-height:1.75; white-space:pre-wrap; word-break:break-word; border-radius:3px; padding:2px 3px; margin:-2px -3px; font-family:var(--sans); cursor:text; margin-left:52px; }
128→    .scene-body-text:empty { display:none; }
129→    .scene-body-text:focus { background:var(--surface3); outline:none; }
130→    .outline-panel.collapsed-view .scene-body-text { display:none; }
131→
132→    /* ── Resizer ── */
133→    .resizer { width:4px; flex-shrink:0; background:var(--border); cursor:col-resize; transition:background .15s; position:relative; z-index:10; }
134→    .resizer:hover, .resizer.dragging { background:var(--accent); }
135→
136→    /* ── Right panel ── */
137→    .right-panel { width:360px; min-width:200px; max-width:70vw; border-left:none; display:flex; flex-direction:column; overflow:hidden; flex-shrink:0; }
138→
139→    /* ── Source detail panel ── */
140→    .source-placeholder { flex:1; display:flex; align-items:center; justify-content:center; color:var(--text-muted); font-size:11px; text-align:center; padding:20px; line-height:1.6; }
141→    .source-inner { display:none; flex-direction:column; flex:1; overflow:hidden; }
142→    .source-inner.visible { display:flex; }
143→    .source-header { padding:12px 14px 8px; border-bottom:1px solid var(--border); flex-shrink:0; }
144→    .source-scene-id { font-size:10px; color:var(--text-muted); letter-spacing:.06em; text-transform:uppercase; margin-bottom:3px; }
145→    .source-scene-title { font-size:13.5px; font-weight:600; color:var(--title-color); line-height:1.3; }
146→    .source-body { flex:1; overflow-y:auto; padding:14px 16px 24px; font-family:var(--serif); font-size:13px; line-height:1.9; color:var(--text); white-space:pre-wrap; word-break:break-word; cursor:text; }
147→    .source-body:focus { outline:none; }
148→    .btn-save { border-color:var(--accent); color:var(--accent); }
149→    .btn-save:hover { background:var(--accent); color:var(--bg); }
150→    .source-body::-webkit-scrollbar { width:3px; }
151→    .source-body::-webkit-scrollbar-thumb { background:var(--border2); border-radius:2px; }
152→    .source-body strong, .source-body b { color:var(--title-color); font-weight:600; }
153→    .source-none { flex:1; display:flex; align-items:center; justify-content:center; color:var(--text-muted); font-size:11px; text-align:center; padding:20px; line-height:1.7; }
154→    .source-body:empty::before { content:'点击此处开始添加场景细节…'; color:var(--text-muted); font-style:italic; font-family:var(--sans); pointer-events:none; }
155→  </style>
156→</head>
157→<body data-theme="dark">
158→
159→<div class="drop-overlay">将 .md 文件拖放到这里</div>
160→<div class="toast" id="toast"></div>
161→
162→<!-- Top bar -->
163→<div class="topbar">
164→  <span class="topbar-title" id="topTitle">大纲编辑器</span>
165→  <span class="sep">|</span>
166→  <span class="topbar-meta" id="topMeta">—</span>
167→  <div class="spacer"></div>
168→  <div class="view-toggle">
169→    <button class="active" id="btnExpand" onclick="expandLevel()">展开</button>
170→    <button id="btnCollapse" onclick="collapseLevel()">折叠</button>
171→  </div>
172→  <div class="theme-wrap">
173→    <button class="btn" onclick="toggleThemePanel(event)">🎨 皮肤</button>
174→    <div class="theme-panel" id="themePanel">
175→      <div class="theme-panel-title">选择风格</div>
176→      <div class="theme-grid" id="themeGrid"></div>
177→    </div>
178→  </div>
179→  <button class="btn" id="importBtn">导入 .md</button>
180→  <button class="btn btn-save" onclick="saveFile()">保存</button>
181→  <button class="btn" onclick="exportClean()">导出大纲</button>
182→  <input type="file" id="fileInput" accept=".md,.txt">
183→</div>
184→
185→<!-- Main -->
186→<div class="main">
187→
188→  <!-- Outline -->
189→  <div class="outline-panel" id="outlinePanel">
190→    <div class="empty-state">
191→      <div class="empty-icon">📄</div>
192→      点击「导入 .md」<br>或将文件拖放到窗口
193→    </div>
194→  </div>
195→
196→  <!-- Resizer -->
197→  <div class="resizer" id="resizer"></div>
198→
199→  <!-- Right panel: source detail -->
200→  <div class="right-panel" id="rightPanel">
201→    <div class="source-placeholder" id="sourcePlaceholder">点击左侧场景查看原文细节</div>
202→    <div class="source-inner" id="sourceInner">
203→      <div class="source-header">
204→        <div class="source-scene-id" id="srcId"></div>
205→        <div class="source-scene-title" id="srcTitle"></div>
206→      </div>
207→      <div class="source-body" id="sourceBody" onblur="onDetailBlur()"></div>
208→      <div class="source-none" id="sourceNone" style="display:none">该场景暂无原文细节</div>
209→    </div>
210→  </div>
211→
212→</div>
213→
214→<script>
215→// ═══════════════════════════════════════════════════════════════════════
216→// THEMES
217→// ═══════════════════════════════════════════════════════════════════════
218→const THEMES = [
219→  { id:'dark',  name:'暗夜', bg:'#111111', accent:'#5a87e8' },
220→  { id:'moon',  name:'月白', bg:'#1c1a18', accent:'#9878e0' },
221→  { id:'paper', name:'纸张', bg:'#f0ead8', accent:'#3a60a8' },
222→  { id:'ocean', name:'深海', bg:'#0b141e', accent:'#38a0d0' },
223→  { id:'amber', name:'暖光', bg:'#160e04', accent:'#c07820' },
224→];
225→const THEME_KEY = 'outline-theme-v1';
226→
227→function buildThemeGrid() {
228→  const cur = localStorage.getItem(THEME_KEY) || 'dark';
229→  document.getElementById('themeGrid').innerHTML = THEMES.map(t =>
230→    `<div class="theme-opt${t.id===cur?' active':''}" onclick="applyTheme('${t.id}')" data-theme-opt="${t.id}">
231→      <div class="theme-swatch" style="background:linear-gradient(135deg,${t.bg} 50%,${t.accent} 100%)"></div>
232→      <span class="theme-name">${t.name}</span>
233→    </div>`
234→  ).join('');
235→}
236→function applyTheme(id) {
237→  document.body.dataset.theme = id;
238→  localStorage.setItem(THEME_KEY, id);
239→  document.querySelectorAll('[data-theme-opt]').forEach(el => el.classList.toggle('active', el.dataset.themeOpt === id));
240→}
241→function toggleThemePanel(e) { e.stopPropagation(); document.getElementById('themePanel').classList.toggle('open'); }
242→document.addEventListener('click', () => document.getElementById('themePanel').classList.remove('open'));
243→document.getElementById('themePanel').addEventListener('click', e => e.stopPropagation());
244→(function(){ const s = localStorage.getItem(THEME_KEY)||'dark'; document.body.dataset.theme=s; buildThemeGrid(); })();
245→
246→// ═══════════════════════════════════════════════════════════════════════
247→// STORAGE
248→// ═══════════════════════════════════════════════════════════════════════
249→const TEXT_KEY = 'outline-text-v1';
250→
251→// ═══════════════════════════════════════════════════════════════════════
252→// STATE
253→// ═══════════════════════════════════════════════════════════════════════
254→let acts = [];
255→let selectedId = null;
256→let viewLevel = 2; // 0=全折叠 1=幕展开 2=章节展开
257→let fileHandle = null;
258→let fileTitle = '';
259→
260→// ═══════════════════════════════════════════════════════════════════════
261→// FILE INPUT
262→// ═══════════════════════════════════════════════════════════════════════
263→document.getElementById('importBtn').addEventListener('click', async () => {
264→  if (window.showOpenFilePicker) {
265→    try {
266→      const [handle] = await window.showOpenFilePicker({
267→        types: [{ description: 'Markdown', accept: {'text/markdown': ['.md','.txt']} }]
268→      });
269→      fileHandle = handle;
270→      loadFile(await handle.getFile());
271→    } catch(e) { /* cancelled */ }
272→  } else {
273→    document.getElementById('fileInput').click();
274→  }
275→});
276→document.getElementById('fileInput').addEventListener('change', function(e) {
277→  const f = e.target.files && e.target.files[0]; if (f) loadFile(f); this.value='';
278→});
279→
280→// ═══════════════════════════════════════════════════════════════════════
281→// PARSER
282→// ═══════════════════════════════════════════════════════════════════════
283→function parseOutline(text) {
284→  const lines = text.replace(/\r\n/g,'\n').replace(/\r/g,'\n').split('\n');
285→  const result = [];
286→  let act=null, chapter=null, scene=null;
287→  let summaryLines=[], bodyLines=[], detailLines=[], actNoteLines=[], inDetail=false;
288→
289→  function flush() {
290→    if (scene) {
291→      scene.summary = summaryLines.join('\n').trimEnd();
292→      scene.body    = bodyLines.join('\n').trimEnd();
293→      scene.detail  = detailLines.join('\n').trim();
294→    }
295→    if (act && !chapter) {
296→      act.notes = actNoteLines.join('\n').trim();
297→    }
298→    summaryLines=[]; bodyLines=[]; detailLines=[]; actNoteLines=[]; inDetail=false; scene=null;
299→  }
300→
301→  for (const raw of lines) {
302→    const line = raw.trim();
303→    if (line.startsWith('## ')&&!line.startsWith('### ')) {
304→      flush(); act={title:line.slice(3).trim(),chapters:[],open:true,notes:''}; chapter=null; result.push(act); continue;
305→    }
306→    if (line.startsWith('### ')) {
307→      if (act && !chapter) { act.notes = actNoteLines.join('\n').trim(); actNoteLines=[]; }
308→      flush(); if(act){chapter={title:line.slice(4).trim(),scenes:[],open:true};act.chapters.push(chapter);} continue;
309→    }
310→    const sm=line.match(/^\*\*(\d+[A-Za-z]+(?:\.\d+)?)[. ]\s*(.+?)\*\*/);
311→    if (sm&&chapter) {
312→      flush(); scene={id:sm[1],title:sm[2].trim(),summary:'',body:'',detail:''}; chapter.scenes.push(scene); continue;
313→    }
314→
315→    // Act-level notes (text under ## before any ###)
316→    if (act && !chapter && !scene) { actNoteLines.push(raw); continue; }
317→    if (!scene) continue;
318→
319→    // <details> block
320→    if (line.startsWith('<details>')) { inDetail=true; continue; }
321→    if (line==='</details>') { inDetail=false; continue; }
322→    if (inDetail) { detailLines.push(raw); continue; }
323→
324→    // Summary (> lines)
325→    if (raw.startsWith('> ') || raw==='>') {
326→      summaryLines.push(raw.startsWith('> ') ? raw.slice(2) : ''); continue;
327→    }
328→
329→    // Everything else → body (for brief scenes without > summary)
330→    if (!line.startsWith('#') && !line.startsWith('```')) bodyLines.push(raw);
331→  }
332→  flush(); return result;
333→}
334→
335→function loadFile(file) {
336→  showToast('正在读取…');
337→  const reader = new FileReader();
338→  reader.onerror = () => showToast('文件读取失败', true);
339→  reader.onload = function(e) {
340→    try {
341→      const text = e.target.result;
342→      acts = parseOutline(text);
343→      let total = 0; acts.forEach(a=>a.chapters.forEach(c=>total+=c.scenes.length));
344→      if (!total) { showToast('未识别到场景，请确认格式', true); return; }
345→      const fl = text.split('\n')[0].trim();
346→      if (fl.startsWith('# ')) { fileTitle = fl; document.getElementById('topTitle').textContent = fl.slice(2).trim(); }
347→      localStorage.setItem(TEXT_KEY, text);
348→      renderOutline(); refreshMeta();
349→      showToast('已载入 ' + total + ' 个场景');
350→    } catch(err) { showToast('解析出错：' + err.message, true); console.error(err); }
351→  };
352→  reader.readAsText(file, 'UTF-8');
353→}
354→
355→// ═══════════════════════════════════════════════════════════════════════
356→// RENDER OUTLINE
357→// ═══════════════════════════════════════════════════════════════════════
358→function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
359→function ea(s){return esc(s).replace(/'/g,'&#39;');}
360→function chevron(){return '<svg class="chevron" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><polyline points="2,4 6,8 10,4"/></svg>';}
