362→function renderOutline() {
363→  const panel = document.getElementById('outlinePanel');
364→  let html = '';
365→  acts.forEach(function(act, ai) {
366→    html += '<div class="act'+(act.open?'':' collapsed')+'" id="act-'+ai+'">';
367→    html += '<div class="act-header" onclick="toggleAct('+ai+');selectAct('+ai+')">'+chevron()+esc(act.title)+'</div>';
368→    html += '<div class="act-body'+(act.open?'':' hidden')+'">';
369→    act.chapters.forEach(function(ch, ci) {
370→      html += '<div class="chapter'+(ch.open?'':' collapsed')+'" id="ch-'+ai+'-'+ci+'">';
371→      html += '<div class="chapter-header" onclick="toggleChapter('+ai+','+ci+')">'+chevron()+esc(ch.title)+'</div>';
372→      html += '<div class="chapter-body'+(ch.open?'':' hidden')+'">';
373→      ch.scenes.forEach(function(sc) {
374→        const dotOn = sc.detail ? ' on' : '';
375→        const sel = sc.id === selectedId ? ' selected' : '';
376→        const displayText = sc.summary || sc.body;
377→        const body = displayText ? '<div class="scene-body-text" contenteditable="true" data-id="'+ea(sc.id)+'" onfocus="selectScene(\''+ea(sc.id)+'\')" onblur="onSummaryBlur(this)" onkeydown="handleBodyKey(event)">'+esc(displayText)+'</div>' : '';
378→        html += '<div class="scene-item'+sel+'" data-id="'+ea(sc.id)+'">';
379→        html += '<div class="scene-content">';
380→        html += '<div class="scene-title-row">';
381→        html += '<div class="scene-left"><div class="dot-btn" onclick="selectScene(\''+ea(sc.id)+'\')" title="查看原文"><div class="dot'+dotOn+'" data-dot="'+ea(sc.id)+'"></div></div><span class="scene-id">'+esc(sc.id)+'</span></div>';
382→        html += '<span class="scene-title-text" contenteditable="true" data-id="'+ea(sc.id)+'" data-field="title" onfocus="selectScene(\''+ea(sc.id)+'\')" onblur="onEditBlur(this)" onclick="event.stopPropagation()" onkeydown="handleTitleKey(event)">'+esc(sc.title)+'</span>';
