535→async function saveFile() {
536→  if(!acts.length){showToast('请先导入大纲',true);return;}
537→  const text=serializeOutline();
538→  localStorage.setItem(TEXT_KEY,text);
539→  if(!fileHandle && window.showSaveFilePicker){
540→    try{
541→      fileHandle=await window.showSaveFilePicker({
542→        suggestedName:(fileTitle?fileTitle.slice(2).trim():'main-outline')+'.md',
543→        types:[{description:'Markdown',accept:{'text/markdown':['.md']}}]
544→      });
545→    }catch(e){return;}
546→  }
547→  if(fileHandle){
548→    try{
549→      const w=await fileHandle.createWritable();
550→      await w.write(text); await w.close();
551→      showToast('已保存');
552→    }catch(e){showToast('保存失败：'+e.message,true);}
553→  } else {
554→    const a=document.createElement('a');
555→    a.href=URL.createObjectURL(new Blob([text],{type:'text/markdown;charset=utf-8'}));
556→    a.download=(fileTitle?fileTitle.slice(2).trim():'main-outline')+'.md';
557→    a.click();
