570→    act.chapters.forEach(ch=>{
571→      lines.push('### '+ch.title,'');
572→      ch.scenes.forEach(sc=>{
573→        lines.push('**'+sc.id+'. '+sc.title+'**');
574→        const t=sc.summary||sc.body; if(t)lines.push(t);
575→        lines.push('');
576→      });
577→    });
578→  });
579→  const a=document.createElement('a');
580→  a.href=URL.createObjectURL(new Blob([lines.join('\n')],{type:'text/markdown;charset=utf-8'}));
