590→// ═══════════════════════════════════════════════════════════════════════
591→// DRAG & DROP
592→// ═══════════════════════════════════════════════════════════════════════
593→window.addEventListener('keydown',e=>{if((e.metaKey||e.ctrlKey)&&e.key==='s'){e.preventDefault();saveFile();}},true);
594→document.addEventListener('dragenter',e=>{if(e.dataTransfer.types&&Array.from(e.dataTransfer.types).includes('Files'))document.body.classList.add('dragging');});
595→document.addEventListener('dragleave',e=>{if(!e.relatedTarget)document.body.classList.remove('dragging');});
596→document.addEventListener('dragover',e=>e.preventDefault());
597→document.addEventListener('drop',e=>{e.preventDefault();document.body.classList.remove('dragging');const f=e.dataTransfer.files&&e.dataTransfer.files[0];if(f)loadFile(f);});
598→
599→// ═══════════════════════════════════════════════════════════════════════
600→// RESIZER
601→// ═══════════════════════════════════════════════════════════════════════
602→(function(){
603→  const RKEY = 'outline-rpanel-width-v1';
604→  const resizer = document.getElementById('resizer');
605→  const rightPanel = document.getElementById('rightPanel');
606→  const saved = parseInt(localStorage.getItem(RKEY), 10);
607→  if (saved && saved >= 200) rightPanel.style.width = saved + 'px';
608→
609→  let startX, startW;
610→  resizer.addEventListener('mousedown', function(e) {
611→    e.preventDefault();
612→    startX = e.clientX;
613→    startW = rightPanel.offsetWidth;
614→    resizer.classList.add('dragging');
615→    document.body.style.cursor = 'col-resize';
616→    document.body.style.userSelect = 'none';
617→
618→    function onMove(e) {
619→      const delta = startX - e.clientX;
620→      const newW = Math.max(200, Math.min(window.innerWidth * 0.7, startW + delta));
621→      rightPanel.style.width = newW + 'px';
622→    }
623→    function onUp() {
624→      localStorage.setItem(RKEY, parseInt(rightPanel.style.width, 10));
625→      resizer.classList.remove('dragging');
626→      document.body.style.cursor = '';
627→      document.body.style.userSelect = '';
628→      document.removeEventListener('mousemove', onMove);
629→      document.removeEventListener('mouseup', onUp);
630→    }
631→    document.addEventListener('mousemove', onMove);
632→    document.addEventListener('mouseup', onUp);
633→  });
634→})();
635→
636→// ═══════════════════════════════════════════════════════════════════════
637→// AUTO-RESTORE
638→// ═══════════════════════════════════════════════════════════════════════
639→(function(){
640→  try {
641→    const text = localStorage.getItem(TEXT_KEY);
642→    if(!text) return;
643→    acts = parseOutline(text);
644→    let t=0; acts.forEach(a=>a.chapters.forEach(c=>t+=c.scenes.length));
645→    if(!t) return;
646→    const fl = text.split('\n')[0].trim();
647→    if(fl.startsWith('# ')) document.getElementById('topTitle').textContent = fl.slice(2).trim();
648→    renderOutline(); refreshMeta();
649→  } catch(e) { console.warn(e); }
650→})();
651→</script>
652→</body>
653→</html>
