package com.mdtool.service;

import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.mdtool.dto.UserInfo;
import com.mdtool.entity.SysUser;
import com.mdtool.exception.BizException;
import com.mdtool.exception.ErrorCode;
import com.mdtool.mapper.SysUserMapper;
import com.mdtool.util.JwtUtil;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.core.ParameterizedTypeReference;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestTemplate;

import java.time.LocalDateTime;
import java.util.List;
import java.util.Map;

@Slf4j
@Service
public class AuthService {

    private final SysUserMapper sysUserMapper;
    private final JwtUtil jwtUtil;
    private final RestTemplate restTemplate;

    @Value("${spring.security.oauth2.client.registration.default.client-id}")
    private String clientId;

    @Value("${spring.security.oauth2.client.registration.default.client-secret}")
    private String clientSecret;

    @Value("${spring.security.oauth2.client.provider.default.token-uri}")
    private String tokenUri;

    public AuthService(SysUserMapper sysUserMapper, JwtUtil jwtUtil) {
        this.sysUserMapper = sysUserMapper;
        this.jwtUtil = jwtUtil;
        this.restTemplate = new RestTemplate();
    }

    /**
     * OAuth2 回调：code 换 token，提取用户信息，同步本地用户表，签发 JWT
     */
    public String handleOAuthCallback(String code, String redirectUri) {
        Map<String, Object> tokenResponse = exchangeToken(code, redirectUri);
        log.info("[mdtool][Auth][OAUTH] token 响应: {}", tokenResponse);

        @SuppressWarnings("unchecked")
        Map<String, Object> oaUserInfo = (Map<String, Object>) tokenResponse.get("user_info");
        if (oaUserInfo == null) {
            log.error("[mdtool][Auth][OAUTH] token 响应中没有 user_info 字段, keys={}", tokenResponse.keySet());
            throw new BizException(ErrorCode.INTERNAL_ERROR);
        }

        String email = (String) oaUserInfo.get("email");
        String displayName = (String) oaUserInfo.get("nickname");

        SysUser user = sysUserMapper.selectOne(
                new LambdaQueryWrapper<SysUser>().eq(SysUser::getUsername, email));

        // 管理员判断逻辑
        boolean isAdmin = "扶苏".equals(displayName);

        if (user != null) {
            user.setOaUserId(email);
            user.setDisplayName(displayName);
            user.setIsAdmin(isAdmin);
            user.setUpdatedAt(LocalDateTime.now());
            sysUserMapper.updateById(user);
            log.info("[mdtool][Auth][LOGIN] 用户登录(已存在), userId={}, email={}", user.getId(), email);
        } else {
            user = SysUser.builder()
                    .oaUserId(email)
                    .username(email)
                    .displayName(displayName)
                    .isAdmin(isAdmin)
                    .createdAt(LocalDateTime.now())
                    .updatedAt(LocalDateTime.now())
                    .build();
            sysUserMapper.insert(user);
            log.info("[mdtool][Auth][LOGIN] 用户首次登录(新建), userId={}, email={}", user.getId(), email);
        }

        return jwtUtil.generateToken(user.getId(), user.getIsAdmin());
    }

    /**
     * Dev 环境登录
     */
    public String devLogin() {
        String devOaUserId = "dev-mock-001";
        SysUser user = sysUserMapper.selectOne(
                new LambdaQueryWrapper<SysUser>().eq(SysUser::getOaUserId, devOaUserId));

        if (user == null) {
            user = SysUser.builder()
                    .oaUserId(devOaUserId)
                    .username("dev_user")
                    .displayName("开发测试用户")
                    .isAdmin(true)
                    .createdAt(LocalDateTime.now())
                    .updatedAt(LocalDateTime.now())
                    .build();
            sysUserMapper.insert(user);
            log.info("[mdtool][Auth][LOGIN] Dev 模式: 创建 mock 用户, userId={}", user.getId());
        }

        return jwtUtil.generateToken(user.getId(), user.getIsAdmin());
    }

    public UserInfo getCurrentUser(Long userId) {
        SysUser user = sysUserMapper.selectById(userId);
        if (user == null) {
            throw new BizException(ErrorCode.NOT_FOUND);
        }
        UserInfo info = new UserInfo();
        info.setId(user.getId());
        info.setOaUserId(user.getOaUserId());
        info.setUsername(user.getUsername());
        info.setDisplayName(user.getDisplayName());
        info.setIsAdmin(user.getIsAdmin());
        return info;
    }

    private Map<String, Object> exchangeToken(String code, String redirectUri) {
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setAccept(List.of(MediaType.APPLICATION_JSON));

        MultiValueMap<String, String> params = new LinkedMultiValueMap<>();
        params.add("grant_type", "authorization_code");
        params.add("client_id", clientId);
        params.add("client_secret", clientSecret);
        params.add("code", code);
        params.add("redirect_uri", redirectUri);

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(params, headers);
        ResponseEntity<Map<String, Object>> response = restTemplate.exchange(
                tokenUri, HttpMethod.POST, request, new ParameterizedTypeReference<>() {});

        Map<String, Object> body = response.getBody();
        if (body == null || !body.containsKey("access_token")) {
            log.error("[mdtool][Auth][OAUTH] 换取 token 失败, responseBody={}", body);
            throw new BizException(ErrorCode.INTERNAL_ERROR);
        }
        return body;
    }
}

package com.mdtool.controller;

import com.mdtool.dto.Result;
import com.mdtool.dto.UserInfo;
import com.mdtool.service.AuthService;
import jakarta.servlet.http.HttpServletRequest;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.core.env.Environment;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.util.UriComponentsBuilder;

import java.util.Arrays;

@Slf4j
@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final AuthService authService;
    private final Environment environment;

    @Value("${spring.security.oauth2.client.registration.default.client-id}")
    private String clientId;

    @Value("${spring.security.oauth2.client.provider.default.authorization-uri}")
    private String authorizationUri;

    @Value("${spring.security.oauth2.client.registration.default.scope:openid,profile,email}")
    private String scope;

    @Value("${app.frontend-url:http://localhost:5174}")
    private String frontendUrl;

    public AuthController(AuthService authService, Environment environment) {
        this.authService = authService;
        this.environment = environment;
    }

    private boolean isDevProfile() {
        return Arrays.asList(environment.getActiveProfiles()).contains("dev");
    }

    @GetMapping("/oauth2/login")
    public ResponseEntity<Void> login(HttpServletRequest request) {
        if (isDevProfile()) {
            String token = authService.devLogin();
            String callbackUrl = frontendUrl + "/oauth/callback?token=" + token;
            log.info("[mdtool][Auth][LOGIN] Dev 模式: 跳过 OAuth2, 直接重定向到前端");
            return ResponseEntity.status(HttpStatus.FOUND)
                    .header(HttpHeaders.LOCATION, callbackUrl)
                    .build();
        }

        String redirectUri = buildRedirectUri(request);
        var builder = UriComponentsBuilder.fromHttpUrl(authorizationUri)
                .queryParam("client_id", clientId)
                .queryParam("redirect_uri", redirectUri)
                .queryParam("response_type", "code");
        if (scope != null && !scope.isBlank()) {
            builder.queryParam("scope", scope);
        }
        String authorizeUrl = builder.toUriString();

        return ResponseEntity.status(HttpStatus.FOUND)
                .header(HttpHeaders.LOCATION, authorizeUrl)
                .build();
    }

    @GetMapping("/oauth2/callback")
    public ResponseEntity<Void> callback(@RequestParam("code") String code,
                                         HttpServletRequest request) {
        String redirectUri = buildRedirectUri(request);
        String token = authService.handleOAuthCallback(code, redirectUri);
        log.info("[mdtool][Auth][CALLBACK] OAuth2 回调完成, 重定向到前端");

        String callbackUrl = frontendUrl + "/oauth/callback?token=" + token;
        return ResponseEntity.status(HttpStatus.FOUND)
                .header(HttpHeaders.LOCATION, callbackUrl)
                .build();
    }

    @GetMapping("/me")
    public Result<UserInfo> me() {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        Long userId = Long.parseLong(auth.getName());
        return Result.ok(authService.getCurrentUser(userId));
    }

    private String buildRedirectUri(HttpServletRequest request) {
        String scheme = request.getScheme();
        String serverName = request.getServerName();
        int serverPort = request.getServerPort();

        StringBuilder sb = new StringBuilder();
        sb.append(scheme).append("://").append(serverName);
        if (("http".equals(scheme) && serverPort != 80)
                || ("https".equals(scheme) && serverPort != 443)) {
            sb.append(":").append(serverPort);
        }
        sb.append("/api/auth/oauth2/callback");
        return sb.toString();
    }
}

