import java.time.LocalDateTime;
import java.util.List;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class DocumentService {

    private final MdDocumentMapper documentMapper;

    /**
     * 获取当前用户的文档列表（不含 content）
     */
    public List<DocumentDTO> listByUser(Long userId) {
        List<MdDocument> docs = documentMapper.selectList(
                new LambdaQueryWrapper<MdDocument>()
                        .eq(MdDocument::getUserId, userId)
                        .orderByDesc(MdDocument::getUpdatedAt));
        return docs.stream().map(this::toDTO).collect(Collectors.toList());
    }

    /**
     * 获取文档详情（含 content）
     */
    public MdDocument getById(Long docId, Long userId) {
        MdDocument doc = documentMapper.selectById(docId);
        if (doc == null || !doc.getUserId().equals(userId)) {
            throw new BizException(ErrorCode.DOC_NOT_FOUND);
        }
        return doc;
    }

    /**
     * 保存文档：id 为空则新建，否则更新
     */
    public MdDocument save(DocumentSaveRequest req, Long userId) {
        if (req.getId() != null) {
            // 更新
            MdDocument existing = documentMapper.selectById(req.getId());
            if (existing == null || !existing.getUserId().equals(userId)) {
                throw new BizException(ErrorCode.DOC_NOT_FOUND);
            }
            existing.setTitle(req.getTitle());
            existing.setContent(req.getContent());
            existing.setUpdatedAt(LocalDateTime.now());
            documentMapper.updateById(existing);
            log.info("[mdtool][Doc][SAVE] 更新文档, docId={}, userId={}, title={}", existing.getId(), userId, req.getTitle());
            return existing;
        }

        // 新建
        MdDocument doc = MdDocument.builder()
                .userId(userId)
                .title(req.getTitle())
                .content(req.getContent())
                .createdAt(LocalDateTime.now())
                .updatedAt(LocalDateTime.now())
                .deleted(0)
                .build();
        documentMapper.insert(doc);
        log.info("[mdtool][Doc][SAVE] 新建文档, docId={}, userId={}, title={}", doc.getId(), userId, req.getTitle());
        return doc;
    }

    /**
     * 删除文档（逻辑删除）
     */
    public void delete(Long docId, Long userId) {
        MdDocument doc = documentMapper.selectById(docId);
        if (doc == null || !doc.getUserId().equals(userId)) {
            throw new BizException(ErrorCode.DOC_NOT_FOUND);
        }
        documentMapper.deleteById(docId);
        log.info("[mdtool][Doc][DELETE] 删除文档, docId={}, userId={}", docId, userId);
    }

    private DocumentDTO toDTO(MdDocument doc) {
        DocumentDTO dto = new DocumentDTO();
        dto.setId(doc.getId());
        dto.setTitle(doc.getTitle());
        dto.setCreatedAt(doc.getCreatedAt());
        dto.setUpdatedAt(doc.getUpdatedAt());
        return dto;
    }
}

