275→async function apiFetch(url, options = {}) {
276→  const token = getToken();
277→  if (!token) { showLoginOverlay(); throw new Error('未登录'); }
278→  const headers = { 'Authorization': 'Bearer ' + token, ...options.headers };
279→  if (options.body && typeof options.body === 'object') {
280→    headers['Content-Type'] = 'application/json';
281→    options.body = JSON.stringify(options.body);
282→  }
283→  const resp = await fetch(url, { ...options, headers });
284→  if (resp.status === 401) { clearToken(); showLoginOverlay(); throw new Error('登录过期'); }
285→  const data = await resp.json();
286→  if (data.code !== 200) { throw new Error(data.message || '请求失败'); }
287→  return data.data;
288→}
