409→// ═══════════════════════════════════════════════════════════════════════
410→// PARSER (与原版完全一致)
411→// ═══════════════════════════════════════════════════════════════════════
412→function parseOutline(text) {
413→  const lines = text.replace(/\r\n/g,'\n').replace(/\r/g,'\n').split('\n');
414→  const result = [];
415→  let act=null, chapter=null, scene=null;
416→  let summaryLines=[], bodyLines=[], detailLines=[], actNoteLines=[], inDetail=false;
417→
418→  function flush() {
419→    if (scene) {
420→      scene.summary = summaryLines.join('\n').trimEnd();
421→      scene.body    = bodyLines.join('\n').trimEnd();
422→      scene.detail  = detailLines.join('\n').trim();
423→    }
424→    if (act && !chapter) {
425→      act.notes = actNoteLines.join('\n').trim();
426→    }
427→    summaryLines=[]; bodyLines=[]; detailLines=[]; actNoteLines=[]; inDetail=false; scene=null;
428→  }
429→
430→  for (const raw of lines) {
431→    const line = raw.trim();
432→    if (line.startsWith('## ')&&!line.startsWith('### ')) {
433→      flush(); act={title:line.slice(3).trim(),chapters:[],open:true,notes:''}; chapter=null; result.push(act); continue;
434→    }
435→    if (line.startsWith('### ')) {
436→      if (act && !chapter) { act.notes = actNoteLines.join('\n').trim(); actNoteLines=[]; }
437→      flush(); if(act){chapter={title:line.slice(4).trim(),scenes:[],open:true};act.chapters.push(chapter);} continue;
438→    }
439→    const sm=line.match(/^\*\*(\d+[A-Za-z]+(?:\.\d+)?)[. ]\s*(.+?)\*\*/);
440→    if (sm&&chapter) {
441→      flush(); scene={id:sm[1],title:sm[2].trim(),summary:'',body:'',detail:''}; chapter.scenes.push(scene); continue;
442→    }
443→    if (act && !chapter && !scene) { actNoteLines.push(raw); continue; }
444→    if (!scene) continue;
445→    if (line.startsWith('<details>')) { inDetail=true; continue; }
446→    if (line==='</details>') { inDetail=false; continue; }
447→    if (inDetail) { detailLines.push(raw); continue; }
448→    if (raw.startsWith('> ') || raw==='>') {
449→      summaryLines.push(raw.startsWith('> ') ? raw.slice(2) : ''); continue;
450→    }
451→    if (!line.startsWith('#') && !line.startsWith('```')) bodyLines.push(raw);
452→  }
453→  flush(); return result;
454→}
