626→// SERIALIZE (与原版完全一致)
627→// ═══════════════════════════════════════════════════════════════════════
628→function serializeOutline() {
629→  const lines=[];
630→  if(fileTitle) lines.push(fileTitle,'');
631→  acts.forEach(act=>{
632→    lines.push('## '+act.title,'');
633→    if(act.notes) lines.push(act.notes,'');
634→    act.chapters.forEach(ch=>{
635→      lines.push('### '+ch.title,'');
636→      ch.scenes.forEach(sc=>{
637→        lines.push('**'+sc.id+'. '+sc.title+'**');
638→        if(sc.summary){
639→          sc.summary.split('\n').forEach(l=>lines.push('> '+l));
640→        } else if(sc.body){
641→          lines.push(sc.body);
642→        }
643→        if(sc.detail){
644→          lines.push('','<details><summary>场景细节</summary>','',sc.detail,'','</details>');
645→        }
646→        lines.push('');
647→      });
648→    });
649→  });
650→  return lines.join('\n');
651→}
