710→document.addEventListener('drop',e=>{e.preventDefault();document.body.classList.remove('dragging');const f=e.dataTransfer.files&&e.dataTransfer.files[0];if(f)loadFile(f);});
711→
712→// ═══════════════════════════════════════════════════════════════════════
713→// RESIZER (与原版完全一致)
714→// ═══════════════════════════════════════════════════════════════════════
715→(function(){
716→  const RKEY = 'outline-rpanel-width-v1';
717→  const resizer = document.getElementById('resizer');
718→  const rightPanel = document.getElementById('rightPanel');
719→  const saved = parseInt(localStorage.getItem(RKEY), 10);
720→  if (saved && saved >= 200) rightPanel.style.width = saved + 'px';
721→
722→  let startX, startW;
723→  resizer.addEventListener('mousedown', function(e) {
724→    e.preventDefault();
725→    startX = e.clientX;
726→    startW = rightPanel.offsetWidth;
727→    resizer.classList.add('dragging');
728→    document.body.style.cursor = 'col-resize';
729→    document.body.style.userSelect = 'none';
730→
731→    function onMove(e) {
732→      const delta = startX - e.clientX;
733→      const newW = Math.max(200, Math.min(window.innerWidth * 0.7, startW + delta));
734→      rightPanel.style.width = newW + 'px';
735→    }
736→    function onUp() {
737→      localStorage.setItem(RKEY, parseInt(rightPanel.style.width, 10));
738→      resizer.classList.remove('dragging');
739→      document.body.style.cursor = '';
740→      document.body.style.userSelect = '';
741→      document.removeEventListener('mousemove', onMove);
742→      document.removeEventListener('mouseup', onUp);
743→    }
744→    document.addEventListener('mousemove', onMove);
745→    document.addEventListener('mouseup', onUp);
746→  });
747→})();
748→
749→// ═══════════════════════════════════════════════════════════════════════
750→// INIT
751→// ═══════════════════════════════════════════════════════════════════════
752→(async function init() {
753→  if (!getToken()) {
754→    showLoginOverlay();
755→    return;
756→  }
757→  hideLoginOverlay();
758→  try {
759→    await apiFetch('/api/auth/me');
760→    loadDocList();
761→  } catch (e) {
762→    // token 无效，显示登录
763→    showLoginOverlay();
764→  }
765→})();
766→</script>
767→</body>
768→</html>
