.doc-item-time { font-size:9px; color:var(--text-muted); margin-top:2px; }
.btn-new-doc { background:none; border:1px solid var(--border2); color:var(--text-dim); padding:2px 8px; border-radius:4px; font-size:11px; cursor:pointer; }
.btn-new-doc:hover { border-color:var(--accent); color:var(--accent); }

/* ── Outline panel ── */
.outline-panel { flex:1; overflow-y:auto; padding:6px 0 40px; min-width:0; }
.outline-panel::-webkit-scrollbar { width:3px; }
.outline-panel::-webkit-scrollbar-thumb { background:var(--border2); border-radius:2px; }
.empty-state { display:flex; flex-direction:column; align-items:center; justify-content:center; height:100%; gap:8px; color:var(--text-muted); font-size:13px; text-align:center; line-height:1.7; padding:40px; }
.empty-icon { font-size:26px; opacity:.35; margin-bottom:6px; }

.act-header { display:flex; align-items:center; gap:6px; padding:12px 16px 5px; cursor:pointer; font-size:10px; font-weight:700; color:var(--act-color); letter-spacing:.1em; text-transform:uppercase; }
.act-header:hover { color:var(--text-dim); }
.chapter-header { display:flex; align-items:center; gap:6px; padding:5px 16px 5px 30px; cursor:pointer; font-size:11.5px; font-weight:600; color:var(--ch-color); border-bottom:1px solid var(--border); }
.chapter-header:hover { background:var(--surface2); }
.chevron { width:10px; height:10px; flex-shrink:0; transition:transform .4s ease; color:var(--text-muted); }
.collapsed > .act-header .chevron, .collapsed > .chapter-header .chevron { transform:rotate(-90deg); }
.act-body, .chapter-body { overflow:hidden; max-height:4000px; transition:max-height .45s ease; }
.act-body.hidden, .chapter-body.hidden { max-height:0; }

.scene-item { border-bottom:1px solid var(--border); }
.scene-item.selected { background:var(--selected-bg); }

.scene-content { padding:8px 16px 9px 36px; min-width:0; }
.scene-title-row { display:flex; align-items:center; margin-bottom:3px; }
.scene-left { display:flex; align-items:center; gap:6px; width:52px; flex-shrink:0; }
.dot-btn { display:flex; align-items:center; justify-content:center; width:14px; flex-shrink:0; cursor:pointer; }
.dot { width:6px; height:6px; border-radius:50%; background:var(--dot-off); transition:background .2s; flex-shrink:0; }
.dot.on { background:var(--dot-on); }
.dot-btn:hover .dot { background:var(--accent); opacity:.7; }
.scene-id { font-size:10px; color:var(--text-muted); letter-spacing:.05em; flex-shrink:0; }
.scene-title-text { font-size:13px; font-weight:600; color:var(--title-color); line-height:1.4; outline:none; border-radius:3px; padding:1px 3px; margin:-1px -3px; cursor:text; }
.scene-title-text:focus { background:var(--surface3); }
.scene-body-text { font-size:12.5px; color:var(--body-color); line-height:1.75; white-space:pre-wrap; word-break:break-word; border-radius:3px; padding:2px 3px; margin:-2px -3px; font-family:var(--sans); cursor:text; margin-left:52px; }
.scene-body-text:empty { display:none; }
.scene-body-text:focus { background:var(--surface3); outline:none; }
.outline-panel.collapsed-view .scene-body-text { display:none; }

/* ── Resizer ── */
.resizer { width:4px; flex-shrink:0; background:var(--border); cursor:col-resize; transition:background .15s; position:relative; z-index:10; }
.resizer:hover, .resizer.dragging { background:var(--accent); }

/* ── Right panel ── */
.right-panel { width:360px; min-width:200px; max-width:70vw; border-left:none; display:flex; flex-direction:column; overflow:hidden; flex-shrink:0; }

/* ── Source detail panel ── */
.source-placeholder { flex:1; display:flex; align-items:center; justify-content:center; color:var(--text-muted); font-size:11px; text-align:center; padding:20px; line-height:1.6; }
.source-inner { display:none; flex-direction:column; flex:1; overflow:hidden; }
.source-inner.visible { display:flex; }
.source-header { padding:12px 14px 8px; border-bottom:1px solid var(--border); flex-shrink:0; }
.source-scene-id { font-size:10px; color:var(--text-muted); letter-spacing:.06em; text-transform:uppercase; margin-bottom:3px; }
.source-scene-title { font-size:13.5px; font-weight:600; color:var(--title-color); line-height:1.3; }
.source-body { flex:1; overflow-y:auto; padding:14px 16px 24px; font-family:var(--serif); font-size:13px; line-height:1.9; color:var(--text); white-space:pre-wrap; word-break:break-word; cursor:text; }
.source-body:focus { outline:none; }
.btn-save { border-color:var(--accent); color:var(--accent); }
.btn-save:hover { background:var(--accent); color:var(--bg); }
.source-body::-webkit-scrollbar { width:3px; }
.source-body::-webkit-scrollbar-thumb { background:var(--border2); border-radius:2px; }
.source-body strong, .source-body b { color:var(--title-color); font-weight:600; }
.source-none { flex:1; display:flex; align-items:center; justify-content:center; color:var(--text-muted); font-size:11px; text-align:center; padding:20px; line-height:1.7; }
.source-body:empty::before { content:'点击此处开始添加场景细节…'; color:var(--text-muted); font-style:italic; font-family:var(--sans); pointer-events:none; }

