import { defineConfig } from 'vite'
import path from 'path'

export default defineConfig({
  server: {
    host: '0.0.0.0',
    port: 5174,
    proxy: {
      '/api': {
        target: 'http://localhost:18081',
        changeOrigin: true,
      },
    },
  },
  plugins: [
    {
      name: 'doc-id-rewrite',
      configureServer(server) {
        // /123/admin.html → 加载 admin.html，前端从 URL 解析 ID
        // /123/ 或 /123 → 加载 index.html
        server.middlewares.use((req, res, next) => {
          const match = req.url.match(/^\/(\d+)(\/admin\.html.*)$/)
          if (match) {
            req.url = '/admin.html' + (match[2].replace(/^\/admin\.html/, '') || '')
            return next()
          }
          const match2 = req.url.match(/^\/(\d+)(\/?)$/)
          if (match2) {
            req.url = '/index.html'
            return next()
          }
          next()
        })
      },
    },
  ],
  build: {
    outDir: 'dist',
    rollupOptions: {
      input: {
        main: path.resolve(__dirname, 'index.html'),
        admin: path.resolve(__dirname, 'admin.html'),
      },
    },
  },
})

