// ═══════════════════════════════════════════════════════════════════════
// RENDER OUTLINE
// ═══════════════════════════════════════════════════════════════════════
function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function ea(s){return esc(s).replace(/'/g,'&#39;');}
function chevron(){return '<svg class="chevron" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><polyline points="2,4 6,8 10,4"/></svg>';}

function renderOutline() {
  const panel = document.getElementById('outlinePanel');
  let html = '';
  acts.forEach(function(act, ai) {
    html += '<div class="act'+(act.open?'':' collapsed')+'" id="act-'+ai+'">';
    html += '<div class="act-header" onclick="toggleAct('+ai+');selectAct('+ai+')">'+chevron()+esc(act.title)+'</div>';
    html += '<div class="act-body'+(act.open?'':' hidden')+'">';
    act.chapters.forEach(function(ch, ci) {
      html += '<div class="chapter'+(ch.open?'':' collapsed')+'" id="ch-'+ai+'-'+ci+'">';
      html += '<div class="chapter-header" onclick="toggleChapter('+ai+','+ci+')">'+chevron()+esc(ch.title)+'</div>';
      html += '<div class="chapter-body'+(ch.open?'':' hidden')+'">';
      ch.scenes.forEach(function(sc) {
        const dotOn = sc.detail ? ' on' : '';
        const sel = sc.id === selectedId ? ' selected' : '';
        const displayText = sc.summary || sc.body;
        const body = displayText ? '<div class="scene-body-text" contenteditable="true" data-id="'+ea(sc.id)+'" onfocus="selectScene(\''+ea(sc.id)+'\')" onblur="onSummaryBlur(this)" onkeydown="handleBodyKey(event)">'+esc(displayText)+'</div>' : '';
        html += '<div class="scene-item'+sel+'" data-id="'+ea(sc.id)+'">';
        html += '<div class="scene-content">';
        html += '<div class="scene-title-row">';
        html += '<div class="scene-left"><div class="dot-btn" onclick="selectScene(\''+ea(sc.id)+'\')" title="查看原文"><div class="dot'+dotOn+'" data-dot="'+ea(sc.id)+'"></div></div><span class="scene-id">'+esc(sc.id)+'</span></div>';
        html += '<span class="scene-title-text" contenteditable="true" data-id="'+ea(sc.id)+'" data-field="title" onfocus="selectScene(\''+ea(sc.id)+'\')" onblur="onEditBlur(this)" onclick="event.stopPropagation()" onkeydown="handleTitleKey(event)">'+esc(sc.title)+'</span>';
        html += '</div>';
        html += body+'</div></div>';
      });
      html += '</div></div>';
    });
    html += '</div></div>';
  });
  panel.innerHTML = html;
}

function onEditBlur(el) {
  const id=el.dataset.id, field=el.dataset.field, val=el.innerText;
  for(const act of acts) for(const ch of act.chapters) {
    const sc=ch.scenes.find(s=>s.id===id); if(sc){sc[field]=val;break;}
  }
}
function handleTitleKey(e){e.stopPropagation();if(e.key==='Enter'){e.preventDefault();e.target.blur();}}
function onSummaryBlur(el) {
  const id=el.dataset.id, val=el.innerText;
  for(const act of acts) for(const ch of act.chapters){
    const sc=ch.scenes.find(s=>s.id===id);
    if(sc){sc.summary?(sc.summary=val):(sc.body=val);break;}
  }
}
function handleBodyKey(e){e.stopPropagation();if(e.key==='Enter'){e.preventDefault();document.execCommand('insertLineBreak');}}

function toggleAct(ai){acts[ai].open=!acts[ai].open;const el=document.getElementById('act-'+ai);el.classList.toggle('collapsed');el.querySelector('.act-body').classList.toggle('hidden');}
function toggleChapter(ai,ci){acts[ai].chapters[ci].open=!acts[ai].chapters[ci].open;const el=document.getElementById('ch-'+ai+'-'+ci);el.classList.toggle('collapsed');el.querySelector('.chapter-body').classList.toggle('hidden');}

// ═══════════════════════════════════════════════════════════════════════
// SELECT ACT / SCENE
// ═══════════════════════════════════════════════════════════════════════
function selectAct(ai) {
  if(selectedId){const p=document.querySelector('.scene-item[data-id="'+selectedId+'"]');if(p)p.classList.remove('selected');}
  selectedId=null;
  const act=acts[ai]; if(!act)return;
  document.getElementById('sourcePlaceholder').style.display='none';
  document.getElementById('sourceInner').classList.add('visible');
  document.getElementById('srcId').textContent='ACT';
  document.getElementById('srcTitle').textContent=act.title;
  const sb=document.getElementById('sourceBody');
  sb.contentEditable='true'; sb.textContent=act.notes||''; sb.style.display='block';
  document.getElementById('sourceNone').style.display='none';
  sb.dataset.actIndex=ai; sb.dataset.mode='act';
}

function selectScene(id) {
  if(selectedId){const p=document.querySelector('.scene-item[data-id="'+selectedId+'"]');if(p)p.classList.remove('selected');}
  selectedId=id;

