// URL ROUTING: /123/admin.html 或 /123/ 解析文档 ID
// ═══════════════════════════════════════════════════════════════════════
function getDocIdFromUrl() {
  const m = window.location.pathname.match(/^\/(\d+)(\/|\/admin\.html)?$/);
  return m ? parseInt(m[1], 10) : null;
}

function getPageName() {
  // 判断当前是 admin 还是 editor 页面
  return window.location.pathname.includes('admin') ? 'admin.html' : '';
}

function buildDocUrl(docId) {
  const page = getPageName();
  return page ? '/' + docId + '/' + page : '/' + docId + '/';
}

function updateUrlForDoc(docId) {
  const newUrl = buildDocUrl(docId);
  window.history.pushState({ docId }, '', newUrl);
}

