(function(){
  const RKEY = 'outline-rpanel-width-v1';
  const resizer = document.getElementById('resizer');
  const rightPanel = document.getElementById('rightPanel');
  const saved = parseInt(localStorage.getItem(RKEY), 10);
  if (saved && saved >= 200) rightPanel.style.width = saved + 'px';

  let startX, startW;
  resizer.addEventListener('mousedown', function(e) {
    e.preventDefault();
    startX = e.clientX;
    startW = rightPanel.offsetWidth;
    resizer.classList.add('dragging');
    document.body.style.cursor = 'col-resize';
    document.body.style.userSelect = 'none';

    function onMove(e) {
      const delta = startX - e.clientX;
      const newW = Math.max(200, Math.min(window.innerWidth * 0.7, startW + delta));
      rightPanel.style.width = newW + 'px';
    }
    function onUp() {
      localStorage.setItem(RKEY, parseInt(rightPanel.style.width, 10));
      resizer.classList.remove('dragging');
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
    }
    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
  });
})();

