// ═══════════════════════════════════════════════════════════════════════
// STATE
// ═══════════════════════════════════════════════════════════════════════
let acts = [];
let selectedId = null;
let viewLevel = 2;
let fileTitle = '';
let currentDocId = null;

// ═══════════════════════════════════════════════════════════════════════
// PARSER
// ═══════════════════════════════════════════════════════════════════════
function parseOutline(text) {
  const lines = text.replace(/\r\n/g,'\n').replace(/\r/g,'\n').split('\n');
  const result = [];
  let act=null, chapter=null, scene=null;
  let summaryLines=[], bodyLines=[], detailLines=[], actNoteLines=[], inDetail=false;

  function flush() {
    if (scene) {
      scene.summary = summaryLines.join('\n').trimEnd();
      scene.body    = bodyLines.join('\n').trimEnd();
      scene.detail  = detailLines.join('\n').trim();
    }
    if (act && !chapter) {
      act.notes = actNoteLines.join('\n').trim();
    }
    summaryLines=[]; bodyLines=[]; detailLines=[]; actNoteLines=[]; inDetail=false; scene=null;
  }

  for (const raw of lines) {
    const line = raw.trim();
    if (line.startsWith('## ')&&!line.startsWith('### ')) {
      flush(); act={title:line.slice(3).trim(),chapters:[],open:true,notes:''}; chapter=null; result.push(act); continue;
    }
    if (line.startsWith('### ')) {
      if (act && !chapter) { act.notes = actNoteLines.join('\n').trim(); actNoteLines=[]; }
      flush(); if(act){chapter={title:line.slice(4).trim(),scenes:[],open:true};act.chapters.push(chapter);} continue;
    }
    const sm=line.match(/^\*\*(\d+[A-Za-z]+(?:\.\d+)?)[. ]\s*(.+?)\*\*/);
    if (sm&&chapter) {
      flush(); scene={id:sm[1],title:sm[2].trim(),summary:'',body:'',detail:''}; chapter.scenes.push(scene); continue;
    }
    if (act && !chapter && !scene) { actNoteLines.push(raw); continue; }
    if (!scene) continue;
    if (line.startsWith('<details>')) { inDetail=true; continue; }
    if (line==='</details>') { inDetail=false; continue; }
    if (inDetail) { detailLines.push(raw); continue; }
    if (raw.startsWith('> ') || raw==='>') {
      summaryLines.push(raw.startsWith('> ') ? raw.slice(2) : ''); continue;
    }
    if (!line.startsWith('#') && !line.startsWith('```')) bodyLines.push(raw);
  }
  flush(); return result;
}

// ═══════════════════════════════════════════════════════════════════════
// RENDER OUTLINE
// ═══════════════════════════════════════════════════════════════════════
function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function ea(s){return esc(s).replace(/'/g,'&#39;');}
function chevron(){return '<svg class="chevron" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><polyline points="2,4 6,8 10,4"/></svg>';}

function renderOutline() {
  const panel = document.getElementById('outlinePanel');
  let html = '';
  acts.forEach(function(act, ai) {
    html += '<div class="act'+(act.open?'':' collapsed')+'" id="act-'+ai+'">';
    html += '<div class="act-header" onclick="toggleAct('+ai+');selectAct('+ai+')">'+chevron()+esc(act.title)+'</div>';
    html += '<div class="act-body'+(act.open?'':' hidden')+'">';
    act.chapters.forEach(function(ch, ci) {
      html += '<div class="chapter'+(ch.open?'':' collapsed')+'" id="ch-'+ai+'-'+ci+'">';
      html += '<div class="chapter-header" onclick="toggleChapter('+ai+','+ci+')">'+chevron()+esc(ch.title)+'</div>';
      html += '<div class="chapter-body'+(ch.open?'':' hidden')+'">';
      ch.scenes.forEach(function(sc) {
        const dotOn = sc.detail ? ' on' : '';
        const sel = sc.id === selectedId ? ' selected' : '';
        const displayText = sc.summary || sc.body;
        const body = displayText ? '<div class="scene-body-text" contenteditable="true" data-id="'+ea(sc.id)+'" onfocus="selectScene(\''+ea(sc.id)+'\')" onblur="onSummaryBlur(this)" onkeydown="handleBodyKey(event)">'+esc(displayText)+'</div>' : '';
        html += '<div class="scene-item'+sel+'" data-id="'+ea(sc.id)+'">';
        html += '<div class="scene-content">';
        html += '<div class="scene-title-row">';
        html += '<div class="scene-left"><div class="dot-btn" onclick="selectScene(\''+ea(sc.id)+'\')" title="查看原文"><div class="dot'+dotOn+'" data-dot="'+ea(sc.id)+'"></div></div><span class="scene-id">'+esc(sc.id)+'</span></div>';
        html += '<span class="scene-title-text" contenteditable="true" data-id="'+ea(sc.id)+'" data-field="title" onfocus="selectScene(\''+ea(sc.id)+'\')" onblur="onEditBlur(this)" onclick="event.stopPropagation()" onkeydown="handleTitleKey(event)">'+esc(sc.title)+'</span>';
        html += '</div>';
        html += body+'</div></div>';
      });
      html += '</div></div>';
    });
    html += '</div></div>';
  });
  panel.innerHTML = html;
}

function onEditBlur(el) {
  const id=el.dataset.id, field=el.dataset.field, val=el.innerText;
  for(const act of acts) for(const ch of act.chapters) {
    const sc=ch.scenes.find(s=>s.id===id); if(sc){sc[field]=val;break;}
  }
}
function handleTitleKey(e){e.stopPropagation();if(e.key==='Enter'){e.preventDefault();e.target.blur();}}
function onSummaryBlur(el) {
  const id=el.dataset.id, val=el.innerText;
  for(const act of acts) for(const ch of act.chapters){
    const sc=ch.scenes.find(s=>s.id===id);
    if(sc){sc.summary?(sc.summary=val):(sc.body=val);break;}
  }
}
function handleBodyKey(e){e.stopPropagation();if(e.key==='Enter'){e.preventDefault();document.execCommand('insertLineBreak');}}

function toggleAct(ai){acts[ai].open=!acts[ai].open;const el=document.getElementById('act-'+ai);el.classList.toggle('collapsed');el.querySelector('.act-body').classList.toggle('hidden');}
function toggleChapter(ai,ci){acts[ai].chapters[ci].open=!acts[ai].chapters[ci].open;const el=document.getElementById('ch-'+ai+'-'+ci);el.classList.toggle('collapsed');el.querySelector('.chapter-body').classList.toggle('hidden');}

// ═══════════════════════════════════════════════════════════════════════
// SELECT ACT / SCENE
// ═══════════════════════════════════════════════════════════════════════
function selectAct(ai) {
  if(selectedId){const p=document.querySelector('.scene-item[data-id="'+selectedId+'"]');if(p)p.classList.remove('selected');}
  selectedId=null;
  const act=acts[ai]; if(!act)return;
  document.getElementById('sourcePlaceholder').style.display='none';
  document.getElementById('sourceInner').classList.add('visible');
  document.getElementById('srcId').textContent='ACT';
  document.getElementById('srcTitle').textContent=act.title;
  const sb=document.getElementById('sourceBody');
  sb.contentEditable='true'; sb.textContent=act.notes||''; sb.style.display='block';
  document.getElementById('sourceNone').style.display='none';
  sb.dataset.actIndex=ai; sb.dataset.mode='act';
}

function selectScene(id) {
  if(selectedId){const p=document.querySelector('.scene-item[data-id="'+selectedId+'"]');if(p)p.classList.remove('selected');}
  selectedId=id;
  const c=document.querySelector('.scene-item[data-id="'+id+'"]');if(c)c.classList.add('selected');
  let title=id, detail='';
  outer:for(const act of acts)for(const ch of act.chapters){
    const sc=ch.scenes.find(s=>s.id===id);
    if(sc){title=sc.title;detail=sc.detail||'';break outer;}
  }
  document.getElementById('sourcePlaceholder').style.display='none';
  document.getElementById('sourceInner').classList.add('visible');
  document.getElementById('srcId').textContent=id;
  document.getElementById('srcTitle').textContent=title;
  const sb=document.getElementById('sourceBody');
  sb.contentEditable='true'; sb.textContent=detail; sb.style.display='block';
  sb.dataset.mode='scene'; delete sb.dataset.actIndex;
  document.getElementById('sourceNone').style.display='none';
}

// ═══════════════════════════════════════════════════════════════════════
// VIEW
// ═══════════════════════════════════════════════════════════════════════
function expandLevel(){ if(viewLevel<2){viewLevel++;applyLevel();} }
function collapseLevel(){ if(viewLevel>0){viewLevel--;applyLevel();} }
function applyLevel(){
  const actsOpen = viewLevel>=1;
  const chaptersOpen = viewLevel>=2;
  acts.forEach(function(act,ai){
    act.open=actsOpen;
    const el=document.getElementById('act-'+ai); if(!el)return;
    el.classList.toggle('collapsed',!actsOpen);
    el.querySelector('.act-body').classList.toggle('hidden',!actsOpen);
    act.chapters.forEach(function(ch,ci){
      ch.open=chaptersOpen;
      const cel=document.getElementById('ch-'+ai+'-'+ci); if(!cel)return;
      cel.classList.toggle('collapsed',!chaptersOpen);
      cel.querySelector('.chapter-body').classList.toggle('hidden',!chaptersOpen);
    });
  });
  document.getElementById('btnExpand').classList.toggle('active',viewLevel===2);
  document.getElementById('btnCollapse').classList.toggle('active',viewLevel===0);
}

// ═══════════════════════════════════════════════════════════════════════
// META
// ═══════════════════════════════════════════════════════════════════════
function refreshMeta(){
  let total=0; acts.forEach(a=>a.chapters.forEach(c=>total+=c.scenes.length));
  document.getElementById('topMeta').textContent = total ? total+'个场景' : '—';
}

// ═══════════════════════════════════════════════════════════════════════
// DETAIL EDIT
// ═══════════════════════════════════════════════════════════════════════
function onDetailBlur() {
  const sb=document.getElementById('sourceBody');
  const val=sb.innerText;
  if(sb.dataset.mode==='act'){
    const ai=parseInt(sb.dataset.actIndex);
    if(acts[ai]) acts[ai].notes=val;
    return;
  }
  if (!selectedId) return;
  outer: for(const act of acts) for(const ch of act.chapters){
    const sc=ch.scenes.find(s=>s.id===selectedId);
    if(sc){
      sc.detail=val;
      const dot=document.querySelector('.dot[data-dot="'+selectedId+'"]');
      if(dot) dot.classList.toggle('on', !!val.trim());
      break outer;
    }
  }
}

// ═══════════════════════════════════════════════════════════════════════
// SERIALIZE
// ═══════════════════════════════════════════════════════════════════════
function serializeOutline() {
  const lines=[];
  if(fileTitle) lines.push(fileTitle,'');
  acts.forEach(act=>{
    lines.push('## '+act.title,'');
    if(act.notes) lines.push(act.notes,'');
    act.chapters.forEach(ch=>{
      lines.push('### '+ch.title,'');
      ch.scenes.forEach(sc=>{
        lines.push('**'+sc.id+'. '+sc.title+'**');
        if(sc.summary){
          sc.summary.split('\n').forEach(l=>lines.push('> '+l));
        } else if(sc.body){
          lines.push(sc.body);
        }
        if(sc.detail){
          lines.push('','<details><summary>场景细节</summary>','',sc.detail,'','</details>');
        }
        lines.push('');
      });
    });
  });
  return lines.join('\n');
}

// ═══════════════════════════════════════════════════════════════════════
// DOC LIST
// ═══════════════════════════════════════════════════════════════════════
function formatTime(t) {
  if (!t) return '';
  const d = new Date(t);
  return d.toLocaleDateString('zh-CN') + ' ' + d.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' });
}

async function loadDocList() {
  try {
    const docs = await apiFetch('/api/doc/list');
    const list = document.getElementById('docList');
    if (!docs || docs.length === 0) {
      list.innerHTML = '<div style="padding:12px;color:var(--text-muted);font-size:11px;text-align:center;">暂无文档</div>';
      return;
    }
    list.innerHTML = docs.map(d =>
      `<a class="doc-item${d.id === currentDocId ? ' active' : ''}" href="${buildDocUrl(d.id)}" onclick="event.preventDefault();openDocument(${d.id})" data-doc-id="${d.id}">
        ${esc(d.title || '无标题')}
        <div class="doc-item-time">${formatTime(d.updatedAt)}</div>
      </a>`
    ).join('');
  } catch (e) {
    console.warn('加载文档列表失败:', e);
  }
}

async function openDocument(id, skipPushState) {
  try {
    showToast('加载中…');
    const doc = await apiFetch('/api/doc/' + id);
    currentDocId = doc.id;
    if (!skipPushState) { updateUrlForDoc(doc.id); }
    const text = doc.content || '';
    acts = parseOutline(text);
    let total = 0; acts.forEach(a => a.chapters.forEach(c => total += c.scenes.length));
    const fl = text.split('\n')[0].trim();
    if (fl.startsWith('# ')) { fileTitle = fl; document.getElementById('topTitle').textContent = fl.slice(2).trim(); }
    else { fileTitle = ''; document.getElementById('topTitle').textContent = doc.title || '大纲编辑器'; }
    renderOutline(); refreshMeta(); loadDocList();
    showToast('已载入 ' + total + ' 个场景');
  } catch (e) {
    showToast('加载失败: ' + e.message, true);
  }
}

// 页面加载时根据 URL 自动打开文档
function autoLoadFromUrl() {
  const id = getDocIdFromUrl();
  if (id) { openDocument(id, true); }
}

// ═══════════════════════════════════════════════════════════════════════
// SAVE TO SERVER
// ═══════════════════════════════════════════════════════════════════════
async function saveToServer() {
  if (!acts.length) { showToast('请先导入大纲', true); return; }
  const content = serializeOutline();
  const title = fileTitle ? fileTitle.slice(2).trim() : '未命名大纲';

  try {
    showToast('保存中…');
    const doc = await apiFetch('/api/doc/save', {
      method: 'POST',
      body: { id: currentDocId, title, content },
    });
    currentDocId = doc.id;
    showToast('已保存');
    loadDocList();
  } catch (e) {
    showToast('保存失败: ' + e.message, true);
  }
}

// ═══════════════════════════════════════════════════════════════════════
// EXPORT
// ═══════════════════════════════════════════════════════════════════════
function exportClean(){
  if(!acts.length){showToast('请先导入大纲',true);return;}
  const lines=[];
  acts.forEach(act=>{
    lines.push('## '+act.title,'');
    act.chapters.forEach(ch=>{
      lines.push('### '+ch.title,'');
      ch.scenes.forEach(sc=>{
        lines.push('**'+sc.id+'. '+sc.title+'**');
        const t=sc.summary||sc.body; if(t)lines.push(t);
        lines.push('');
      });
    });
  });
  const a=document.createElement('a');
  a.href=URL.createObjectURL(new Blob([lines.join('\n')],{type:'text/markdown;charset=utf-8'}));
  a.download='outline-clean.md'; a.click();
}

// ═══════════════════════════════════════════════════════════════════════
// TOAST
// ═══════════════════════════════════════════════════════════════════════
let toastTimer;
function showToast(msg,isError){const t=document.getElementById('toast');t.textContent=msg;t.className='toast show'+(isError?' error':'');clearTimeout(toastTimer);toastTimer=setTimeout(()=>t.classList.remove('show'),2500);}

// ═══════════════════════════════════════════════════════════════════════
// KEYBOARD
// ═══════════════════════════════════════════════════════════════════════
window.addEventListener('keydown',e=>{if((e.metaKey||e.ctrlKey)&&e.key==='s'){e.preventDefault();saveToServer();}},true);

// ═══════════════════════════════════════════════════════════════════════
// RESIZER
// ═══════════════════════════════════════════════════════════════════════
(function(){
  const RKEY = 'outline-rpanel-width-v1';
  const resizer = document.getElementById('resizer');
  const rightPanel = document.getElementById('rightPanel');
  const saved = parseInt(localStorage.getItem(RKEY), 10);
  if (saved && saved >= 200) rightPanel.style.width = saved + 'px';

  let startX, startW;
  resizer.addEventListener('mousedown', function(e) {
    e.preventDefault();
    startX = e.clientX;
    startW = rightPanel.offsetWidth;
    resizer.classList.add('dragging');
    document.body.style.cursor = 'col-resize';
    document.body.style.userSelect = 'none';

    function onMove(e) {
      const delta = startX - e.clientX;
      const newW = Math.max(200, Math.min(window.innerWidth * 0.7, startW + delta));
      rightPanel.style.width = newW + 'px';
    }
    function onUp() {
      localStorage.setItem(RKEY, parseInt(rightPanel.style.width, 10));
      resizer.classList.remove('dragging');
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
    }
    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
  });
})();

