/* ── Base ─────────────────────────────────────────────────────── */
:root { --serif:'Georgia','STSong','宋体',serif; --sans:-apple-system,'PingFang SC','Helvetica Neue',sans-serif; }
* { box-sizing:border-box; margin:0; padding:0; }
body { background:var(--bg); color:var(--text); font-family:var(--sans); height:100vh; display:flex; flex-direction:column; overflow:hidden; transition:background .3s,color .3s; }

/* ── Top bar ── */
.topbar { height:44px; background:var(--surface); border-bottom:1px solid var(--border); display:flex; align-items:center; padding:0 14px; gap:10px; flex-shrink:0; user-select:none; }
.topbar-title { font-size:13px; font-weight:600; color:var(--title-color); max-width:300px; white-space:nowrap; overflow:hidden; text-overflow:ellipsis; }
.topbar-meta { font-size:11px; color:var(--text-muted); }
.sep { color:var(--border2); }
.spacer { flex:1; }
.view-toggle { display:flex; border:1px solid var(--border2); border-radius:5px; overflow:hidden; }
.view-toggle button { background:none; border:none; color:var(--text-dim); padding:4px 10px; font-size:11px; cursor:pointer; font-family:var(--sans); transition:all .15s; }
.view-toggle button.active { background:var(--surface3); color:var(--text); }
.btn { background:none; border:1px solid var(--border2); color:var(--text-dim); padding:4px 11px; border-radius:5px; font-size:11px; cursor:pointer; font-family:var(--sans); transition:all .15s; white-space:nowrap; position:relative; }
.btn:hover { border-color:var(--accent); color:var(--accent); }
#fileInput { display:none; }

/* ── Theme picker ── */
.theme-wrap { position:relative; }
.theme-panel { display:none; position:absolute; top:calc(100% + 8px); right:0; background:var(--surface); border:1px solid var(--border2); border-radius:8px; padding:12px; width:230px; z-index:200; box-shadow:0 8px 24px rgba(0,0,0,.4); }
.theme-panel.open { display:block; }
.theme-panel-title { font-size:10px; color:var(--text-dim); letter-spacing:.06em; text-transform:uppercase; margin-bottom:10px; }
.theme-grid { display:grid; grid-template-columns:1fr 1fr; gap:6px; }
.theme-opt { display:flex; align-items:center; gap:8px; padding:7px 9px; border-radius:6px; cursor:pointer; border:1px solid transparent; transition:all .15s; }
.theme-opt:hover { background:var(--surface2); }
.theme-opt.active { border-color:var(--accent); }
.theme-swatch { width:22px; height:22px; border-radius:5px; flex-shrink:0; border:1px solid rgba(255,255,255,.08); }
.theme-name { font-size:12px; color:var(--text); }
.theme-opt.active .theme-name { color:var(--accent); }

/* ── Toast ── */
.toast { position:fixed; bottom:20px; left:50%; transform:translateX(-50%); background:var(--surface3); border:1px solid var(--border2); color:var(--text); padding:7px 15px; border-radius:6px; font-size:12px; opacity:0; transition:opacity .3s; pointer-events:none; z-index:999; white-space:nowrap; }
.toast.show { opacity:1; }
.toast.error { border-color:#c05050; color:#e07070; }

/* ── Drop ── */
.drop-overlay { display:none; position:fixed; inset:0; background:rgba(90,135,232,.06); border:2px dashed var(--accent); z-index:100; pointer-events:none; align-items:center; justify-content:center; font-size:14px; color:var(--accent); }
body.dragging .drop-overlay { display:flex; }

/* ── Layout ── */
.main { display:flex; flex:1; overflow:hidden; }

/* ── Doc list sidebar ── */
.doc-sidebar { width:200px; min-width:140px; background:var(--surface); border-right:1px solid var(--border); display:flex; flex-direction:column; flex-shrink:0; overflow:hidden; }
.doc-sidebar-header { padding:10px 12px; border-bottom:1px solid var(--border); display:flex; align-items:center; justify-content:space-between; }
.doc-sidebar-title { font-size:11px; font-weight:600; color:var(--text-dim); letter-spacing:.05em; text-transform:uppercase; }
.doc-sidebar-list { flex:1; overflow-y:auto; padding:4px 0; }
.doc-sidebar-list::-webkit-scrollbar { width:3px; }
.doc-sidebar-list::-webkit-scrollbar-thumb { background:var(--border2); border-radius:2px; }
.doc-item { padding:7px 12px; cursor:pointer; font-size:12px; color:var(--text-dim); border-left:2px solid transparent; transition:all .15s; white-space:nowrap; overflow:hidden; text-overflow:ellipsis; }
.doc-item:hover { background:var(--surface2); color:var(--text); }
.doc-item.active { border-left-color:var(--accent); color:var(--accent); background:var(--selected-bg); }
.doc-item-time { font-size:9px; color:var(--text-muted); margin-top:2px; }
.btn-new-doc { background:none; border:1px solid var(--border2); color:var(--text-dim); padding:2px 8px; border-radius:4px; font-size:11px; cursor:pointer; }
.btn-new-doc:hover { border-color:var(--accent); color:var(--accent); }

/* ── Outline panel ── */
.outline-panel { flex:1; overflow-y:auto; padding:6px 0 40px; min-width:0; }
.outline-panel::-webkit-scrollbar { width:3px; }
.outline-panel::-webkit-scrollbar-thumb { background:var(--border2); border-radius:2px; }
.empty-state { display:flex; flex-direction:column; align-items:center; justify-content:center; height:100%; gap:8px; color:var(--text-muted); font-size:13px; text-align:center; line-height:1.7; padding:40px; }
.empty-icon { font-size:26px; opacity:.35; margin-bottom:6px; }

.act-header { display:flex; align-items:center; gap:6px; padding:12px 16px 5px; cursor:pointer; font-size:10px; font-weight:700; color:var(--act-color); letter-spacing:.1em; text-transform:uppercase; }
.act-header:hover { color:var(--text-dim); }
.chapter-header { display:flex; align-items:center; gap:6px; padding:5px 16px 5px 30px; cursor:pointer; font-size:11.5px; font-weight:600; color:var(--ch-color); border-bottom:1px solid var(--border); }
.chapter-header:hover { background:var(--surface2); }
.chevron { width:10px; height:10px; flex-shrink:0; transition:transform .4s ease; color:var(--text-muted); }
.collapsed > .act-header .chevron, .collapsed > .chapter-header .chevron { transform:rotate(-90deg); }
.act-body, .chapter-body { overflow:hidden; max-height:4000px; transition:max-height .45s ease; }
.act-body.hidden, .chapter-body.hidden { max-height:0; }

.scene-item { border-bottom:1px solid var(--border); }
.scene-item.selected { background:var(--selected-bg); }

.scene-content { padding:8px 16px 9px 36px; min-width:0; }
.scene-title-row { display:flex; align-items:center; margin-bottom:3px; }
.scene-left { display:flex; align-items:center; gap:6px; width:52px; flex-shrink:0; }
.dot-btn { display:flex; align-items:center; justify-content:center; width:14px; flex-shrink:0; cursor:pointer; }
.dot { width:6px; height:6px; border-radius:50%; background:var(--dot-off); transition:background .2s; flex-shrink:0; }
.dot.on { background:var(--dot-on); }
.dot-btn:hover .dot { background:var(--accent); opacity:.7; }
.scene-id { font-size:10px; color:var(--text-muted); letter-spacing:.05em; flex-shrink:0; }
.scene-title-text { font-size:13px; font-weight:600; color:var(--title-color); line-height:1.4; outline:none; border-radius:3px; padding:1px 3px; margin:-1px -3px; cursor:text; }
.scene-title-text:focus { background:var(--surface3); }
.scene-body-text { font-size:12.5px; color:var(--body-color); line-height:1.75; white-space:pre-wrap; word-break:break-word; border-radius:3px; padding:2px 3px; margin:-2px -3px; font-family:var(--sans); cursor:text; margin-left:52px; }
.scene-body-text:empty { display:none; }
.scene-body-text:focus { background:var(--surface3); outline:none; }
.outline-panel.collapsed-view .scene-body-text { display:none; }

/* ── Resizer ── */
.resizer { width:4px; flex-shrink:0; background:var(--border); cursor:col-resize; transition:background .15s; position:relative; z-index:10; }
.resizer:hover, .resizer.dragging { background:var(--accent); }

/* ── Right panel ── */
.right-panel { width:360px; min-width:200px; max-width:70vw; border-left:none; display:flex; flex-direction:column; overflow:hidden; flex-shrink:0; }

/* ── Source detail panel ── */
.source-placeholder { flex:1; display:flex; align-items:center; justify-content:center; color:var(--text-muted); font-size:11px; text-align:center; padding:20px; line-height:1.6; }
.source-inner { display:none; flex-direction:column; flex:1; overflow:hidden; }
.source-inner.visible { display:flex; }
.source-header { padding:12px 14px 8px; border-bottom:1px solid var(--border); flex-shrink:0; }
