function loadFile(file) {
  showToast('正在读取…');
  currentDocId = null;
  const reader = new FileReader();
  reader.onerror = () => showToast('文件读取失败', true);
  reader.onload = function(e) {
    try {
      const text = e.target.result;
      acts = parseOutline(text);
      let total = 0; acts.forEach(a=>a.chapters.forEach(c=>total+=c.scenes.length));
      if (!total) { showToast('未识别到场景，请确认格式', true); return; }
      const fl = text.split('\n')[0].trim();
      if (fl.startsWith('# ')) { fileTitle = fl; document.getElementById('topTitle').textContent = fl.slice(2).trim(); }
      renderOutline(); refreshMeta();
      showToast('已载入 ' + total + ' 个场景');
    } catch(err) { showToast('解析出错：' + err.message, true); console.error(err); }
  };
  reader.readAsText(file, 'UTF-8');
}

function newDocument() {
  acts = [];
  currentDocId = null;
  fileTitle = '';
  document.getElementById('topTitle').textContent = '大纲编辑器';
  document.getElementById('outlinePanel').innerHTML =
    '<div class="empty-state"><div class="empty-icon">📄</div>点击「导入 .md」或将文件拖放到窗口</div>';
  refreshMeta();
  loadDocList();
}

// Drag & drop（仅管理页支持）
document.addEventListener('dragenter',e=>{if(e.dataTransfer.types&&Array.from(e.dataTransfer.types).includes('Files'))document.body.classList.add('dragging');});
document.addEventListener('dragleave',e=>{if(!e.relatedTarget)document.body.classList.remove('dragging');});
document.addEventListener('dragover',e=>e.preventDefault());
document.addEventListener('drop',e=>{e.preventDefault();document.body.classList.remove('dragging');const f=e.dataTransfer.files&&e.dataTransfer.files[0];if(f)loadFile(f);});

// 删除按钮（在文档列表右键时用，或后续扩展）
async function deleteDocument(id) {
  if (!confirm('确定删除这个文档吗？')) return;
  try {
    await apiFetch('/api/doc/' + id, { method: 'DELETE' });
    if (currentDocId === id) { newDocument(); }
    showToast('已删除');
    loadDocList();
  } catch (e) {
    showToast('删除失败: ' + e.message, true);
  }
}

// Init
loadDocList();
</script>
</body>
</html>

