package com.mdtool.controller;

import com.mdtool.dto.DocumentDTO;
import com.mdtool.dto.DocumentSaveRequest;
import com.mdtool.dto.Result;
import com.mdtool.entity.MdDocument;
import com.mdtool.service.DocumentService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/api/doc")
@RequiredArgsConstructor
public class DocumentController {

    private final DocumentService documentService;

    @GetMapping("/list")
    public Result<List<DocumentDTO>> list() {
        return Result.ok(documentService.listAll());
    }

    @GetMapping("/{id}")
    public Result<MdDocument> detail(@PathVariable Long id) {
        return Result.ok(documentService.getById(id));
    }

    @PostMapping("/save")
    public Result<MdDocument> save(@Valid @RequestBody DocumentSaveRequest req,
                                   HttpServletRequest request) {
        String clientIp = getClientIp(request);
        return Result.ok(documentService.save(req, clientIp));
    }

    @DeleteMapping("/{id}")
    public Result<Void> delete(@PathVariable Long id) {
        documentService.delete(id);
        return Result.ok();
    }

    private String getClientIp(HttpServletRequest request) {
        String ip = request.getHeader("X-Forwarded-For");
        if (ip != null && !ip.isBlank()) {
            // 取第一个（真实客户端 IP）
            ip = ip.split(",")[0].trim();
        }
        if (ip == null || ip.isBlank() || "unknown".equalsIgnoreCase(ip)) {
            ip = request.getHeader("X-Real-IP");
        }
        if (ip == null || ip.isBlank() || "unknown".equalsIgnoreCase(ip)) {
            ip = request.getRemoteAddr();
        }
        return ip;
    }
}

