package com.mdtool.service;

import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.mdtool.dto.DocumentDTO;
import com.mdtool.dto.DocumentSaveRequest;
import com.mdtool.entity.MdDocument;
import com.mdtool.exception.BizException;
import com.mdtool.exception.ErrorCode;
import com.mdtool.mapper.MdDocumentMapper;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;
import java.util.List;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class DocumentService {

    private final MdDocumentMapper documentMapper;

    /**
     * 获取所有文档列表（不含 content）
     */
    public List<DocumentDTO> listAll() {
        List<MdDocument> docs = documentMapper.selectList(
                new LambdaQueryWrapper<MdDocument>()
                        .orderByDesc(MdDocument::getUpdatedAt));
        return docs.stream().map(this::toDTO).collect(Collectors.toList());
    }

    /**
     * 获取文档详情（含 content）
     */
    public MdDocument getById(Long docId) {
        MdDocument doc = documentMapper.selectById(docId);
        if (doc == null) {
            throw new BizException(ErrorCode.DOC_NOT_FOUND);
        }
        return doc;
    }

    /**
     * 保存文档：id 为空则新建，否则更新
     */
    public MdDocument save(DocumentSaveRequest req) {
        if (req.getId() != null) {
            MdDocument existing = documentMapper.selectById(req.getId());
            if (existing == null) {
                throw new BizException(ErrorCode.DOC_NOT_FOUND);
            }
            existing.setTitle(req.getTitle());
            existing.setContent(req.getContent());
            existing.setUpdatedAt(LocalDateTime.now());
            documentMapper.updateById(existing);
            log.info("[mdtool][Doc][SAVE] 更新文档, docId={}, title={}", existing.getId(), req.getTitle());
            return existing;
        }

        MdDocument doc = MdDocument.builder()
                .title(req.getTitle())
                .content(req.getContent())
                .createdAt(LocalDateTime.now())
                .updatedAt(LocalDateTime.now())
                .deleted(0)
                .build();
        documentMapper.insert(doc);
        log.info("[mdtool][Doc][SAVE] 新建文档, docId={}, title={}", doc.getId(), req.getTitle());
        return doc;
    }

    /**
     * 删除文档（逻辑删除）
     */
    public void delete(Long docId) {
        MdDocument doc = documentMapper.selectById(docId);
        if (doc == null) {
            throw new BizException(ErrorCode.DOC_NOT_FOUND);
        }
        documentMapper.deleteById(docId);
        log.info("[mdtool][Doc][DELETE] 删除文档, docId={}", docId);
    }

    private DocumentDTO toDTO(MdDocument doc) {
        DocumentDTO dto = new DocumentDTO();
        dto.setId(doc.getId());
        dto.setTitle(doc.getTitle());
        dto.setCreatedAt(doc.getCreatedAt());
        dto.setUpdatedAt(doc.getUpdatedAt());
        return dto;
    }
}

