// EXPORT
// ═══════════════════════════════════════════════════════════════════════
function exportClean(){
  if(!acts.length){showToast('请先导入大纲',true);return;}
  const lines=[];
  acts.forEach(act=>{
    lines.push('## '+act.title,'');
    act.chapters.forEach(ch=>{
      lines.push('### '+ch.title,'');
      ch.scenes.forEach(sc=>{
        lines.push('**'+sc.id+'. '+sc.title+'**');
        const t=sc.summary||sc.body; if(t)lines.push(t);
        lines.push('');
      });
    });
  });
  const a=document.createElement('a');
  a.href=URL.createObjectURL(new Blob([lines.join('\n')],{type:'text/markdown;charset=utf-8'}));
  a.download='outline-clean.md'; a.click();
}

